1	module moving_avg
2	#(
3	    parameter DATA_WIDTH = 32,
4	    parameter WINDOW_SHIFT = 4,
5	    parameter SIGNED = 0
6	)
7	(
8	    input clock,
9	    input enable,
10	    input reset,
11	
12	    input signed [DATA_WIDTH-1:0] data_in,
13	    input input_strobe,
14	
15	    output reg signed [DATA_WIDTH-1:0] data_out,
16	    output reg output_strobe
17	);
18	
19	localparam WINDOW_SIZE = 1<<WINDOW_SHIFT;
20	localparam SUM_WIDTH = DATA_WIDTH + WINDOW_SHIFT;
21	
22	reg signed [(SUM_WIDTH-1):0] running_sum;
23	
24	wire signed [DATA_WIDTH-1:0] old_data;
25	wire signed [DATA_WIDTH-1:0] new_data = data_in;
26	
27	wire signed [SUM_WIDTH-1:0] ext_old_data = {{WINDOW_SHIFT{old_data[DATA_WIDTH-1]}}, old_data};
28	wire signed [SUM_WIDTH-1:0] ext_new_data = {{WINDOW_SHIFT{new_data[DATA_WIDTH-1]}}, new_data};
29	
30	
31	reg [WINDOW_SHIFT-1:0] addr;
32	reg full;
33	
34	ram_2port  #(.DWIDTH(DATA_WIDTH), .AWIDTH(WINDOW_SHIFT)) delay_line (
35	    .clka(clock),
36	    .ena(1),
37	    .wea(input_strobe),
38	    .addra(addr),
39	    .dia(data_in),
40	    .doa(),
41	    .clkb(clock),
42	    .enb(input_strobe),
43	    .web(0),
44	    .addrb(addr),
45	    .dib(32'hFFFF),
46	    .dob(old_data)
47	);
48	
49	integer i;
50	always @(posedge clock) begin
51	    if (reset) begin
52	        addr <= 0;
53	        running_sum <= 0;
54	        full <= 0;
55	        data_out <= 0;
56	    end else if (enable) begin
57	        if (input_strobe) begin
58	            addr <= addr + 1;
59	            data_out <= running_sum[SUM_WIDTH-1:WINDOW_SHIFT];
60	
61	            if (addr == WINDOW_SIZE-1) begin
62	                full <= 1;
63	            end
64	
65	            if (full) begin
66	                running_sum <= running_sum + ext_new_data- ext_old_data;
67	            end else begin
68	                running_sum <= running_sum + ext_new_data;
69	            end
70	
71	            output_strobe <= full;
72	        end else begin
73	            output_strobe <= 0;
74	        end
75	    end else begin
76	        output_strobe <= 0;
77	    end
78	end
